const items = $input.all();

// District list mapping
const parseLocation = (url, title, desc) => {
  const text = `${url} ${title} ${desc}`.toLowerCase();

  let city = 'Durrës';
  if (text.includes('tirane') || text.includes('tirana') || text.includes('bllok') || text.includes('lake park')) {
    city = 'Tirana';
  }

  let district = 'Plazh';
  if (city === 'Tirana') {
    district = 'Center';
    if (text.includes('bllok')) district = 'Blloku';
    else if (text.includes('lake') || text.includes('liqen')) district = 'Lake Park';
    else if (text.includes('don bosko')) district = 'Don Bosko';
  } else {
    if (text.includes('golem')) district = 'Golem';
    else if (text.includes('qerret')) district = 'Qerret';
    else if (text.includes('vollga')) district = 'Vollga';
    else if (text.includes('mali i robit')) district = 'Mali i Robit';
    else if (text.includes('hamallaj')) district = 'Hamallaj';
    else if (text.includes('lalz')) district = 'Gjiri i Lalzit';
    else if (text.includes('shkembi') || text.includes('kavaj')) district = 'Shkëmbi i Kavajës';
  }

  return { city, district };
};

const formatted = items.map(item => {
  const row = item.json;
  const url = row["URL — посилання на об'єкт."] || '';
  const title = row["Title — назва об'єкта."] || '';
  const desc = row["Description — опис об'єкта."] || '';

  const loc = parseLocation(url, title, desc);

  // Normalize category
  const rawCategory = (row["Category — категорія (Sale або Rent)."] || '').toLowerCase();
  const category = rawCategory.includes('rent') || rawCategory.includes('оренда') ? 'Rent' : 'Sale';

  return {
    url,
    title,
    price: row["Price — ціна."] || '0 €',
    category,
    area: row["Area — площа (м²)."] || '0 m2',
    bedrooms: row["Bedrooms — кількість спалень/кімнат."] || '0',
    description: desc,
    agentName: row["Agent Name — ім'я агента."] || 'Century 21',
    agentPhone: row["Agent Phone — телефон агента."] || '',
    lastModified: row["Last Modified — дата останньої зміни об'єкта на сайті."] || new Date().toISOString(),
    image: row["Image — посилання на фото."] || 'https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?auto=format&fit=crop&w=600&q=80',
    city: loc.city,
    district: loc.district
  };
});

return formatted;
